mapper.select:
SELECT DISTINCT s.id, s.url, s.title, s.source_type, s.summary_json, s.language, s.create_time, t.id AS tag_id, t.name AS tag_name FROM summary s LEFT JOIN summary_tag st ON s.id = st.summary_id LEFT JOIN tag t ON st.tag_id = t.id WHERE s.user_id = #{userId}
AND (s.title LIKE CONCAT('%', #{keyword}, '%') OR JSON_EXTRACT(s.summary_json, '$.one_line_summary') LIKE CONCAT('%', #{keyword}, '%'))
AND s.source_type = #{sourceType}
AND s.id IN (SELECT summary_id FROM summary_tag WHERE tag_id = #{tagId})
ORDER BY s.create_time DESC
